import{_ as r,c as d,o as a,ag as o}from"./chunks/framework.XjE0kKti.js";const e="/gatewayweb/docs/assets/hub0008-overview.Pkcr09c3.png",u=JSON.parse('{"title":"集群节点事件","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0008.md","filePath":"modules/hub0008.md","lastUpdated":null}'),n={name:"modules/hub0008.md"};function s(h,t,l,i,g,b){return a(),d("div",null,[...t[0]||(t[0]=[o('<h1 id="集群节点事件" tabindex="-1">集群节点事件 <a class="header-anchor" href="#集群节点事件" aria-label="Permalink to &quot;集群节点事件&quot;">​</a></h1><p>用于在分布式环境中查看<strong>集群事件</strong>及其在各<strong>处理节点</strong>上的确认与执行结果：左侧为事件列表（谁在何时发布了什么），右侧为与当前选中事件关联的处理记录（各节点是否已收到、处理成功与否）。适合排查配置下发、网关实例联动、节点未同步等问题。</p><p><img src="'+e+'" alt="集群节点事件：事件列表与处理列表"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p><strong>集群节点事件</strong>面向运维与网关管理员，典型用途包括：</p><ul><li><strong>追踪一次集群级操作</strong>：例如某节点触发的配置刷新、实例生命周期类动作等，对应列表中的事件类型与事件动作。</li><li><strong>核对传播范围</strong>：通过右侧处理列表，查看哪些节点生成了确认记录、状态是否为成功或仍在待处理。</li><li><strong>定位失败节点</strong>：结合确认状态、结果信息与重试次数，缩小到具体节点或网络链路。</li></ul><p>事件类型、事件动作的具体取值由业务与后端定义；列表中可能出现如 <code>GATEWAY_INSTANCE</code> 与 <code>RELOAD</code> 等组合，含义以你们环境内的规范为准。</p><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>系统设置</strong> → <strong>集群节点事件</strong>。</p><hr><h2 id="页面布局" tabindex="-1">页面布局 <a class="header-anchor" href="#页面布局" aria-label="Permalink to &quot;页面布局&quot;">​</a></h2><p>页面为<strong>左右分栏</strong>：</p><table tabindex="0"><thead><tr><th>区域</th><th>作用</th></tr></thead><tbody><tr><td>左侧</td><td><strong>集群事件列表</strong>：分页展示事件；单击某行可选中该事件，并驱动右侧刷新。</td></tr><tr><td>右侧</td><td><strong>处理列表（确认列表）</strong>：展示当前选中事件在各处理节点上的确认记录，可单独筛选与分页。</td></tr></tbody></table><p>左侧工具栏提供 <strong>收起处理列表 / 展开处理列表</strong>，用于在宽屏上专注查看事件表，或重新展开右侧对照处理结果。</p><hr><h2 id="左侧-查询集群事件" tabindex="-1">左侧：查询集群事件 <a class="header-anchor" href="#左侧-查询集群事件" aria-label="Permalink to &quot;左侧：查询集群事件&quot;">​</a></h2><h3 id="筛选条件" tabindex="-1">筛选条件 <a class="header-anchor" href="#筛选条件" aria-label="Permalink to &quot;筛选条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>事件类型</td><td>文本输入，支持按类型关键字过滤（占位提示为「请输入事件类型」）。</td></tr><tr><td>事件动作</td><td>下拉筛选；界面提供常见动作选项（如 CREATE、UPDATE、DELETE、REFRESH、INVALIDATE）。实际事件列表中也可能出现其它动作值（如 RELOAD），与网关业务扩展一致。</td></tr><tr><td>活动状态</td><td>全部、活动或非活动。</td></tr></tbody></table><p>点击 <strong>更多条件</strong> 可补充 <strong>发布节点ID</strong>、<strong>发布节点IP</strong>，用于从发布源定位事件。</p><p>使用 <strong>查询</strong> 按条件加载列表；<strong>重置</strong> 清空条件并重新查询。</p><h3 id="列表字段-常见" tabindex="-1">列表字段（常见） <a class="header-anchor" href="#列表字段-常见" aria-label="Permalink to &quot;列表字段（常见）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>说明</th></tr></thead><tbody><tr><td>事件ID</td><td>事件的唯一标识，用于与右侧处理记录关联。</td></tr><tr><td>事件类型</td><td>事件所属业务分类（如网关实例相关等）。</td></tr><tr><td>事件动作</td><td>对该类型资源执行的动作（如重载、刷新等）。</td></tr><tr><td>发布节点 / 发布节点IP</td><td>产生或发布该事件的节点标识与地址。</td></tr><tr><td>事件时间</td><td>事件发生时间。</td></tr><tr><td>活动状态</td><td>活动或非活动。</td></tr></tbody></table><h3 id="行操作" tabindex="-1">行操作 <a class="header-anchor" href="#行操作" aria-label="Permalink to &quot;行操作&quot;">​</a></h3><ul><li><strong>单击行</strong>：选中该事件，右侧处理列表会按该 <strong>事件ID</strong> 重新加载。</li><li><strong>右键菜单</strong>：支持 <strong>查看详情</strong>（打开事件详情对话框），以及复制行或单元格，便于粘贴到工单或日志系统。</li></ul><hr><h2 id="右侧-查询事件处理-确认-记录" tabindex="-1">右侧：查询事件处理（确认）记录 <a class="header-anchor" href="#右侧-查询事件处理-确认-记录" aria-label="Permalink to &quot;右侧：查询事件处理（确认）记录&quot;">​</a></h2><p>右侧数据依赖<strong>左侧当前选中的事件</strong>。未选中事件、或该事件尚无处理记录时，表格可能为空（例如显示「暂无数据」）。</p><h3 id="筛选条件-1" tabindex="-1">筛选条件 <a class="header-anchor" href="#筛选条件-1" aria-label="Permalink to &quot;筛选条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>处理节点ID</td><td>按处理节点标识过滤。</td></tr><tr><td>处理节点IP</td><td>按处理节点 IP 过滤。</td></tr><tr><td>确认状态</td><td>全部、待处理、成功、失败、跳过。</td></tr><tr><td>活动状态</td><td>全部、活动或非活动。</td></tr></tbody></table><p>使用 <strong>查询</strong>、<strong>重置</strong> 与左侧类似；分页仅作用于当前处理列表。</p><h3 id="列表字段-常见-1" tabindex="-1">列表字段（常见） <a class="header-anchor" href="#列表字段-常见-1" aria-label="Permalink to &quot;列表字段（常见）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>列</th><th>说明</th></tr></thead><tbody><tr><td>确认ID</td><td>单条处理记录的主键。</td></tr><tr><td>处理节点ID / 处理节点IP</td><td>执行或回应该事件的节点。</td></tr><tr><td>确认状态</td><td>待处理、成功、失败、跳过等；用于判断该节点侧是否已完成。</td></tr><tr><td>处理时间</td><td>节点侧处理完成或状态变更的时间（无则显示为占位符）。</td></tr><tr><td>重试次数</td><td>失败重试等场景下的计数参考。</td></tr><tr><td>结果信息</td><td>失败原因、跳过原因等文本说明（若有）。</td></tr><tr><td>活动状态</td><td>活动或非活动。</td></tr></tbody></table><p>右键 <strong>查看详情</strong> 可打开处理记录详情（会尽量拉取服务端最新详情）。</p><hr><h2 id="推荐排查流程" tabindex="-1">推荐排查流程 <a class="header-anchor" href="#推荐排查流程" aria-label="Permalink to &quot;推荐排查流程&quot;">​</a></h2><ol><li>在左侧用 <strong>事件类型</strong>、<strong>事件动作</strong> 或 <strong>发布节点</strong> 缩小范围，找到目标 <strong>事件ID</strong>。</li><li><strong>单击选中</strong> 该行，观察右侧是否出现各节点的确认记录。</li><li>在右侧用 <strong>确认状态</strong> 筛出「待处理」或「失败」，结合 <strong>结果信息</strong> 与 <strong>处理节点IP</strong> 登录对应节点或查看采集与网关日志。</li><li>若右侧始终无数据，确认是否已选中事件、事件是否确实会向多节点下发，以及节点连通性与后台任务是否正常。</li></ol><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因与处理</th></tr></thead><tbody><tr><td>右侧一直暂无数据</td><td>未在左侧选中事件；或该事件未产生处理记录；或筛选过严，尝试重置右侧条件。</td></tr><tr><td>部分节点长期待处理</td><td>对应节点离线、消费队列阻塞或版本不兼容；结合节点监控与日志排查。</td></tr><tr><td>事件动作在下拉里找不到</td><td>下拉为常用子集，列表仍可能展示其它动作值；以实际行数据与环境文档为准。</td></tr></tbody></table>',41)])])}const p=r(n,[["render",s]]);export{u as __pageData,p as default};
